#### TypeScript Structural Typing Example
```typescript
// Define the "Duck" shape
interface Quacker {
  quack(): void;
}

// This function expects a Quacker
function makeSound(animal: Quacker) {
  animal.quack();
}

// A Dog class that doesn't inherit from Quacker
class Dog {
  quack() { console.log("Woof quack!"); }
}

// A literal object
const rubberDuck = {
  quack: () => console.log("Squeak!")
};

// TypeScript accepts both because they "look" like a Quacker
makeSound(new Dog());       // Valid
makeSound(rubberDuck);      // Valid
```

